import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---- Quote: base premiums & processing fee ----
  it.todo("empty item list yields premium of 5 (just the processing fee)");
  it.todo("single plain sword (newcomer, first contract): 100 base + 10 first + 5 fee = 115");
  it.todo("single plain amulet (newcomer, first contract): 60 + 6 + 5 = 71");
  it.todo("single plain staff (newcomer, first contract): 80 + 8 + 5 = 93");
  it.todo("single plain potion (newcomer, first contract): 40 + 4 + 5 = 49");
  it.todo("single rune (newcomer, first contract): 25 + 2.5 first + 5 fee → rounded up");
  it.todo("single moonstone (newcomer, first contract): 25 + 2.5 + 5 → rounded up");

  // ---- Component blocks ----
  it.todo("2 runes → base premium 50 (no block)");
  it.todo("3 runes → base premium 60 (block applies)");
  it.todo("4 runes → base premium 100 (no block, requires exactly 3)");
  it.todo("7 runes → base premium 175 (one block + 4 extras → 60 + 100)");
  it.todo("2 runes + 1 moonstone → base premium 75 (different types, no block)");
  it.todo("3 runes + 3 moonstones → base premium 120 (two separate blocks)");

  // ---- Item-specific modifiers ----
  it.todo("cursed sword (newcomer, ench 3): 100 + 50 curse + 10 first + 5 = 165 (newcomer integration example)");
  it.todo("sword with enchantment exactly 5: high-enchantment surcharge applies");
  it.todo("sword with enchantment 4: no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5: both curse and high-enchantment apply");

  // ---- Policy-wide modifiers ----
  it.todo("customer with exactly 2 years: loyalty discount applies");
  it.todo("long-standing customer's second contract with cursed enchanted sword: 160 (integration example)");

  // ---- Multi-item policy: modifier scope ----
  it.todo("cursed sword + plain amulet (newcomer, first contract): cursed surcharge applies only to sword");

  // ---- Rounding ----
  it.todo("premium calculation yielding fraction is rounded UP to whole G");

  // ---- Claim: deductible and reimbursement ----
  it.todo("regular sword damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune damage 200 → payout 100 (full minus 100 deductible)");
  it.todo("sword with enchantment 9, damage 1000 → payout 400 (50% then deductible)");
  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 (full minus deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 (high-enchantment then deductible)");

  // ---- Claim: multiple items / per-item deductible ----
  it.todo("dragon attack damages a 500 sword and a 300 amulet → payout 600 (deductible per item)");
  it.todo("two swords insured, two sword damages → each damage gets its own deductible");

  // ---- Claim: rounding ----
  it.todo("payout calculation yielding fraction is rounded DOWN to whole G");

  // ---- CLI / scenario integration ----
  it.todo("scenario with a quote step then a claim step references policy by index");

  // ---- Error cases ----
  it.todo("quote with unknown item type throws");
  it.todo("claim with item type not in policy throws");
  it.todo("claim with negative damage amount throws");
  it.todo("claim with more damages of a type than the policy covers throws");
});

